import { useState } from 'react';

export default function CartDrawer({ cart, onClose, onCheckout, isUserLoggedIn }) {
  const [showCheckoutForm, setShowCheckoutForm] = useState(false);
  const [placing, setPlacing] = useState(false);
  const [formError, setFormError] = useState('');
  const [checkoutData, setCheckoutData] = useState({
    name: '',
    email: '',
    phone: '',
    address: '',
    paymentMethod: 'upi'
  });

  const formatINR = (amount) =>
    new Intl.NumberFormat('en-IN', {
      style: 'currency',
      currency: 'INR',
      maximumFractionDigits: 0
    }).format(amount);

  // Calculate totals
  const itemsTotal = cart.reduce((sum, item) => sum + item.price, 0);
  const originalTotal = cart.reduce((sum, item) => sum + item.originalPrice, 0);
  const savings = originalTotal - itemsTotal;
  const deliveryCharge = 0; // Free for now
  const handlingCharge = 2;
  const grandTotal = itemsTotal + handlingCharge + deliveryCharge;

  const handleCheckoutClick = async () => {
    if (!isUserLoggedIn) {
      onCheckout();
      return;
    }

    if (!cart.length) {
      setFormError('Cart is empty');
      return;
    }

    setShowCheckoutForm(true);
    setFormError('');
  };

  const handlePlaceOrder = async (event) => {
    event.preventDefault();
    setFormError('');

    if (!checkoutData.name || !checkoutData.phone || !checkoutData.address) {
      setFormError('Name, phone and address are required');
      return;
    }

    setPlacing(true);
    try {
      const payload = {
        customerDetails: {
          name: checkoutData.name,
          email: checkoutData.email,
          phone: checkoutData.phone,
          address: checkoutData.address
        },
        paymentMethod: checkoutData.paymentMethod,
        totalAmount: grandTotal,
        products: cart.map((item) => ({
          product: item._id || undefined,
          name: item.name,
          price: item.price,
          quantity: 1
        }))
      };

      await onCheckout(payload);
      setShowCheckoutForm(false);
      onClose();
    } catch (error) {
      setFormError(error.message || 'Failed to place order');
    } finally {
      setPlacing(false);
    }
  };

  return (
    <div style={{
      position: 'fixed',
      top: 0,
      right: 0,
      width: 410,
      height: '100vh',
      background: '#fff',
      boxShadow: '-8px 0 32px #0002',
      zIndex: 1000,
      display: 'flex',
      flexDirection: 'column',
      fontFamily: 'Poppins, Arial, sans-serif',
      transition: 'right 0.3s',
    }}>
      <div style={{ padding: '22px 28px 16px 18px', borderBottom: '1px solid #f0f0f0', display: 'flex', alignItems: 'center', gap: 12 }}>
        <button onClick={onClose} style={{ background: 'none', border: 'none', fontSize: 28, cursor: 'pointer', color: '#222', fontWeight: 600, marginRight: 8 }}>&larr;</button>
        <span style={{ fontWeight: 700, fontSize: 22, letterSpacing: '-1px' }}>My Cart</span>
        <span style={{ flex: 1 }} />
        <span style={{ color: '#19b955', fontWeight: 600, fontSize: 18, cursor: 'pointer' }}>Share</span>
      </div>
      <div style={{ flex: 1, overflowY: 'auto', padding: 24, background: '#f6faff' }}>
        <div style={{ background: '#eaf3ff', borderRadius: 14, padding: 16, marginBottom: 18, fontWeight: 600, fontSize: 16, color: '#1a73e8', display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
          <span>Your total savings</span>
          <span>{formatINR(savings)}</span>
        </div>
        <div style={{ background: '#fff', borderRadius: 14, padding: 18, marginBottom: 18, boxShadow: '0 2px 12px #e0e0e0' }}>
          <div style={{ color: '#222', fontWeight: 700, fontSize: 16, marginBottom: 8, display: 'flex', alignItems: 'center', gap: 8 }}>
            <span style={{ color: '#19b955', fontSize: 22 }}>⏱️</span> Delivery in 11 minutes
          </div>
          <div style={{ fontSize: 13, color: '#888', marginTop: 2, marginBottom: 10 }}>Shipment of {cart.length} item{cart.length !== 1 ? 's' : ''}</div>
          {cart.map((item, idx) => (
            <div key={idx} style={{ display: 'flex', alignItems: 'center', gap: 12, margin: '14px 0', background: '#f8f8f8', borderRadius: 10, padding: 8 }}>
              <img src={item.image} alt={item.name} style={{ width: 48, height: 48, borderRadius: 8, objectFit: 'cover', border: '1px solid #eee' }} />
              <div style={{ flex: 1 }}>
                <div style={{ fontWeight: 600, fontSize: 15 }}>{item.name}</div>
                <div style={{ color: '#888', fontSize: 13 }}>{item.volume}</div>
                <div style={{ fontWeight: 700, fontSize: 16, color: '#222' }}>{formatINR(item.price)}</div>
              </div>
              {/* Quantity controls can be added here */}
              <span style={{ fontWeight: 600, fontSize: 18, color: '#222' }}>1</span>
            </div>
          ))}
        </div>
        <div style={{ background: '#fff', borderRadius: 14, padding: 18, marginBottom: 18, boxShadow: '0 2px 12px #e0e0e0' }}>
          <div style={{ fontWeight: 700, fontSize: 16, marginBottom: 8 }}>Bill details</div>
          <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 6 }}>
            <span>Items total <span style={{ color: '#1a73e8', fontWeight: 500, fontSize: 13, marginLeft: 6, background: '#eaf3ff', borderRadius: 6, padding: '2px 8px' }}>Saved {formatINR(savings)}</span></span>
            <span style={{ textDecoration: 'line-through', color: '#aaa', marginRight: 8, fontWeight: 500 }}>{formatINR(originalTotal)}</span>
            <span style={{ fontWeight: 700, color: '#222' }}>{formatINR(itemsTotal)}</span>
          </div>
          <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: 6 }}>
            <span>Delivery charge</span>
            <span style={{ color: '#1a73e8', fontWeight: 700 }}>FREE</span>
          </div>
          <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: 6 }}>
            <span>Handling charge</span>
            <span style={{ fontWeight: 600 }}>{formatINR(handlingCharge)}</span>
          </div>
          <div style={{ borderTop: '1px dashed #ddd', margin: '10px 0' }}></div>
          <div style={{ display: 'flex', justifyContent: 'space-between', fontWeight: 700, fontSize: 18, color: '#222' }}>
            <span>Grand total</span>
            <span>{formatINR(grandTotal)}</span>
          </div>
        </div>
        <div style={{ color: '#1a73e8', fontWeight: 700, fontSize: 16, marginBottom: 12, background: '#eaf3ff', borderRadius: 8, padding: '8px 12px', textAlign: 'right' }}>Your total savings {formatINR(savings)}</div>
        <div style={{ background: '#fff', borderRadius: 14, padding: 16, fontSize: 14, color: '#222', boxShadow: '0 2px 12px #e0e0e0', marginBottom: 18 }}>
          <div style={{ fontWeight: 700, marginBottom: 6 }}>Cancellation Policy</div>
          Orders cannot be cancelled once packed for delivery. In case of unexpected delays, a refund will be provided, if applicable.
        </div>
      </div>
      <div style={{ padding: 18, borderTop: '1px solid #eee', background: '#fff', boxShadow: '0 -2px 8px #eee' }}>
        {formError && (
          <div style={{ color: '#dc2626', fontSize: 13, marginBottom: 8 }}>{formError}</div>
        )}

        {showCheckoutForm && (
          <form onSubmit={handlePlaceOrder} style={{ marginBottom: 12, display: 'grid', gap: 8 }}>
            <input
              placeholder="Full name"
              value={checkoutData.name}
              onChange={(e) => setCheckoutData((prev) => ({ ...prev, name: e.target.value }))}
              style={{ border: '1px solid #d1d5db', borderRadius: 8, padding: '8px 10px', fontSize: 13 }}
            />
            <input
              placeholder="Email (optional)"
              value={checkoutData.email}
              onChange={(e) => setCheckoutData((prev) => ({ ...prev, email: e.target.value }))}
              style={{ border: '1px solid #d1d5db', borderRadius: 8, padding: '8px 10px', fontSize: 13 }}
            />
            <input
              placeholder="Phone"
              value={checkoutData.phone}
              onChange={(e) => setCheckoutData((prev) => ({ ...prev, phone: e.target.value }))}
              style={{ border: '1px solid #d1d5db', borderRadius: 8, padding: '8px 10px', fontSize: 13 }}
            />
            <textarea
              placeholder="Delivery address"
              value={checkoutData.address}
              onChange={(e) => setCheckoutData((prev) => ({ ...prev, address: e.target.value }))}
              rows={2}
              style={{ border: '1px solid #d1d5db', borderRadius: 8, padding: '8px 10px', fontSize: 13, resize: 'vertical' }}
            />
            <select
              value={checkoutData.paymentMethod}
              onChange={(e) => setCheckoutData((prev) => ({ ...prev, paymentMethod: e.target.value }))}
              style={{ border: '1px solid #d1d5db', borderRadius: 8, padding: '8px 10px', fontSize: 13 }}
            >
              <option value="upi">UPI</option>
              <option value="credit_card">Credit Card</option>
              <option value="cod">Cash on Delivery</option>
            </select>
            <button
              type="submit"
              disabled={placing}
              style={{ background: '#166534', color: '#fff', border: 'none', borderRadius: 8, padding: '10px 0', cursor: 'pointer', fontSize: 14 }}
            >
              {placing ? 'Placing...' : 'Place Order'}
            </button>
          </form>
        )}

        <button
          style={{
            width: '100%',
            background: 'linear-gradient(90deg, #00c853 60%, #009624 100%)',
            color: '#fff',
            fontWeight: 500,
            fontSize: 20,
            border: 'none',
            borderRadius: 12,
            padding: '15px 0',
            cursor: 'pointer',
            boxShadow: '0 2px 12px #00c85333',
            letterSpacing: '0.01em',
            fontFamily: 'Poppins, Arial, sans-serif',
            transition: 'background 0.2s',
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'space-between',
            gap: 2,
          }}
          onClick={handleCheckoutClick}
        >
          <span style={{ fontWeight: 600, fontSize: 18, marginRight: 2 }}>{formatINR(grandTotal)} <span style={{ fontWeight: 400, fontSize: 15, opacity: 0.85 }}>TOTAL</span></span>
          <span style={{ fontWeight: 500, fontSize: 18, letterSpacing: '0.01em', display: 'flex', alignItems: 'center', marginLeft: 0 }}>
            {isUserLoggedIn ? 'Checkout' : 'Login to Proceed'} <span style={{ fontSize: 22, marginLeft: 2, fontWeight: 400 }}>&#8594;</span>
          </span>
        </button>
      </div>
    </div>
  );
}
